import OpenAI from 'openai';

const openai = new OpenAI({ apiKey: process.env.OPENAI_API_KEY });

// Create vector store and upload files
async function createRAGAssistant() {
  const fileIds = await Promise.all([
    'doc1.pdf', 'doc2.pdf', 'doc3.pdf'
  ].map(async (filePath) => {
    const file = await openai.files.create({
      file: fs.createReadStream(filePath),
      purpose: 'assistants'
    });
    return file.id;
  }));

  const vectorStore = await openai.beta.vectorStores.create({
    name: 'RAG Documents'
  });

  await openai.beta.vectorStores.files.batchCreate(vectorStore.id, {
    file_ids: fileIds
  });

  const assistant = await openai.beta.assistants.create({
    name: 'RAG Assistant',
    instructions: 'Use only provided documents. Always cite sources.',
    model: 'gpt-4-turbo-preview',
    tools: [{ type: 'file_search' }],
    tool_resources: {
      file_search: { vector_store_ids: [vectorStore.id] }
    }
  });

  console.log('Assistant ID:', assistant.id);
  return assistant.id;
}

async function runRAGQuery(threadId: string, assistantId: string) {
  const run = await openai.beta.threads.runs.create(threadId, {
    assistant_id: assistantId
  });

  // Poll until complete
  let status = run.status;
  while (status === 'queued' || status === 'in_progress') {
    await new Promise(resolve => setTimeout(resolve, 1000));
    const updatedRun = await openai.beta.threads.runs.retrieve(
      threadId,
      run.id
    );
    status = updatedRun.status;
  }

  const messages = await openai.beta.threads.messages.list(threadId);
  const message = messages.data[0];

  const citations = message.content[0].annotations
    ?.filter((a: any) => a.type === 'file_citation')
    .map((a: any) => ({
      text: a.text,
      fileId: a.file_citation.file_id,
      quote: a.file_citation.quote
    })) || [];

  return {
    response: message.content[0].text?.value,
    citations
  };
}

