import { Vex } from '@vex/sdk';

const vex = new Vex({ apiKey: process.env.VEX_API_KEY });

// Express webhook endpoint
export const openaiWebhook = async (req: Request, res: Response) => {
  const event = req.body;

  if (event.object === 'thread.run.completed') {
    const runId = event.id;
    const threadId = event.thread_id;

    // Fetch run output
    const openai = new OpenAI({ apiKey: process.env.OPENAI_API_KEY });
    const messages = await openai.beta.threads.messages.list(threadId);
    const message = messages.data[0];

    // Extract RAG artifacts
    const citations = message.content[0].annotations
      ?.filter((a: any) => a.type === 'file_citation') || [];

    // Verify with Vex
    const result = await vex.verify({
      suite_id: 'vex_rag_suite_123',
      input: message.content[0].text?.value || '',
      output: message.content[0].text?.value || '',
      citations: citations.map((c: any) => ({
        text: c.text,
        fileId: c.file_citation.file_id,
        quote: c.file_citation.quote
      })),
      metadata: { run_id: runId, thread_id: threadId }
    });

    // Alert on failure
    if (result.overall_score < 0.8) {
      await sendAlert(`RAG verification failed: ${result.overall_score}`);
    }
  }

  res.status(200).json({ received: true });
};
